# -*- coding: utf-8 -*-
import re, sqlite3

def normalize(text):
    text = re.sub(r'\s+', '', text)
    text = re.sub(r'[？?]', '？', text)
    return text.strip()

def extract_core(text):
    core = re.split(r'\s*[\(（][1１][\)）]', text)[0].strip()
    core = re.split(r'\s*[A-D][\.、]', core)[0].strip()
    return core

