def is_duplicate(q, db_set):
    nq = normalize(q)
    if len(nq) < 8:
        return True
    for db_q in db_set:
        if len(db_q) < 8:
            continue
        if len(nq) >= 12 and len(db_q) >= 12 and nq[:12] == db_q[:12]:
            return True
        if len(nq) > 15 and nq in db_q:
            return True
        if len(db_q) > 15 and db_q in nq:
            return True
    return False

fagui_new = [q for q in fagui_pdf if not is_duplicate(q, db_fagui)]
shiwu_new = [q for q in shiwu_pdf if not is_duplicate(q, db_shiwu)]

