    out.write(f"資料庫法規: {len(db_fagui)} 題, 實務: {len(db_shiwu)} 題\n")
    out.write(f"\n===== 保險法規：PDF共 {len(fagui_pdf)} 題，未重複: {len(fagui_new)} 題 =====\n")
    for i, q in enumerate(fagui_new, 1):
        out.write(f"{i}. {q}\n")
    out.write(f"\n===== 保險實務：PDF共 {len(shiwu_pdf)} 題，未重複: {len(shiwu_new)} 題 =====\n")
    for i, q in enumerate(shiwu_new, 1):
        out.write(f"{i}. {q}\n")

